(window.webpackJsonp=window.webpackJsonp||[]).push([[303],{585:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * @param {number[]} calories\\n * @param {number} k\\n * @param {number} lower\\n * @param {number} upper\\n * @return {number}\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> dietPlanPerformance = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">calories, k, lower, upper</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> p=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;=calories.length-k;i++){\\n      <span class=\\"hljs-keyword\\">let</span> sum=<span class=\\"hljs-number\\">0</span>\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=i;j&lt;i+k;j++){\\n        sum+=calories[j]\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(sum&gt;upper){\\n        p+=<span class=\\"hljs-number\\">1</span>\\n      }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(sum&lt;lower){\\n        p-=<span class=\\"hljs-number\\">1</span>\\n      }\\n    }\\n  <span class=\\"hljs-keyword\\">return</span> p\\n};\\n</code></pre>\\n"],"titleSlug":"diet-plan-performance","hasThinking":false,"content":"<p>\u4f60\u7684\u597d\u53cb\u662f\u4e00\u4f4d\u5065\u8eab\u7231\u597d\u8005\u3002\u524d\u6bb5\u65e5\u5b50\uff0c\u4ed6\u7ed9\u81ea\u5df1\u5236\u5b9a\u4e86\u4e00\u4efd\u5065\u8eab\u8ba1\u5212\u3002\u73b0\u5728\u60f3\u8bf7\u4f60\u5e2e\u4ed6\u8bc4\u4f30\u4e00\u4e0b\u8fd9\u4efd\u8ba1\u5212\u662f\u5426\u5408\u7406\u3002</p>\\n\\n<p>\u4ed6\u4f1a\u6709\u4e00\u4efd\u8ba1\u5212\u6d88\u8017\u7684\u5361\u8def\u91cc\u8868\uff0c\u5176\u4e2d&nbsp;<code>calories[i]</code>&nbsp;\u7ed9\u51fa\u4e86\u4f60\u7684\u8fd9\u4f4d\u597d\u53cb\u5728\u7b2c&nbsp;<code>i</code>&nbsp;\u5929\u9700\u8981\u6d88\u8017\u7684\u5361\u8def\u91cc\u603b\u91cf\u3002</p>\\n\\n<p>\u4e3a\u4e86\u66f4\u597d\u5730\u8bc4\u4f30\u8fd9\u4efd\u8ba1\u5212\uff0c\u5bf9\u4e8e\u5361\u8def\u91cc\u8868\u4e2d\u7684\u6bcf\u4e00\u5929\uff0c\u4f60\u90fd\u9700\u8981\u8ba1\u7b97\u4ed6 \u300c\u8fd9\u4e00\u5929\u4ee5\u53ca\u4e4b\u540e\u7684\u8fde\u7eed\u51e0\u5929\u300d \uff08\u5171&nbsp;<code>k</code> \u5929\uff09\u5185\u6d88\u8017\u7684\u603b\u5361\u8def\u91cc <em>T\uff1a</em></p>\\n\\n<ul>\\n\\t<li>\u5982\u679c&nbsp;<code>T &lt; lower</code>\uff0c\u90a3\u4e48\u8fd9\u4efd\u8ba1\u5212\u76f8\u5bf9\u7cdf\u7cd5\uff0c\u5e76\u5931\u53bb 1 \u5206\uff1b&nbsp;</li>\\n\\t<li>\u5982\u679c <code>T &gt; upper</code>\uff0c\u90a3\u4e48\u8fd9\u4efd\u8ba1\u5212\u76f8\u5bf9\u4f18\u79c0\uff0c\u5e76\u83b7\u5f97 1 \u5206\uff1b</li>\\n\\t<li>\u5426\u5219\uff0c\u8fd9\u4efd\u8ba1\u5212\u666e\u666e\u901a\u901a\uff0c\u5206\u503c\u4e0d\u505a\u53d8\u52a8\u3002</li>\\n</ul>\\n\\n<p>\u8bf7\u8fd4\u56de\u7edf\u8ba1\u5b8c\u6240\u6709&nbsp;<code>calories.length</code>&nbsp;\u5929\u540e\u5f97\u5230\u7684\u603b\u5206\u4f5c\u4e3a\u8bc4\u4f30\u7ed3\u679c\u3002</p>\\n\\n<p>\u6ce8\u610f\uff1a\u603b\u5206\u53ef\u80fd\u662f\u8d1f\u6570\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>calories = [1,2,3,4,5], k = 1, lower = 3, upper = 3\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>calories[0], calories[1] &lt; lower \u800c calories[3], calories[4] &gt; upper, \u603b\u5206 = 0.</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>calories = [3,2], k = 2, lower = 0, upper = 1\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n<strong>\u89e3\u91ca\uff1a</strong>calories[0] + calories[1] &gt; upper, \u603b\u5206 = 1.\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>calories = [6,5,0,0], k = 2, lower = 1, upper = 5\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n<strong>\u89e3\u91ca\uff1a</strong>calories[0] + calories[1] &gt; upper, calories[2] + calories[3] &lt; lower, \u603b\u5206 = 0.\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= k &lt;= calories.length &lt;= 10^5</code></li>\\n\\t<li><code>0 &lt;= calories[i] &lt;= 20000</code></li>\\n\\t<li><code>0 &lt;= lower &lt;= upper</code></li>\\n</ul>\\n"}')}}]);